35	import { newListItemId } from './schema';
36	import type { Json } from './admin-form';
37	
38	const isObject = (value: unknown): value is { readonly [key: string]: Json } =>
39	  typeof value === 'object' && value !== null && !Array.isArray(value);
40	
41	/** Assign a fresh id to a list item that has no `id` key; else leave it alone. */
42	const withId = (item: Json): Json => {
43	  if (!isObject(item)) return item;
44	  if ('id' in item) return item;
45	  return { id: newListItemId(), ...item };
46	};
47	
48	/** Backfill ids on every element of `value` when it is an array of items. */
49	const backfillItems = (value: unknown): readonly Json[] | undefined =>
50	  Array.isArray(value) ? value.map(withId) : undefined;
51	
52	/**
53	 * Return a copy of the parsed `SiteContent` JSON with a fresh id assigned to any
54	 * id-less list item (`conferences[].speakers[]`, `conferences[].seminars[]`,
55	 * `team[]`). Items already carrying an `id` are untouched (idempotent). A value
56	 * that is not the expected shape is returned as-is so the decoder — not this
57	 * normalizer — is the one to reject it.
58	 */
59	export const backfillListItemIds = (document: unknown): unknown => {
60	  if (!isObject(document)) return document;
61	
62	  const next: Record<string, Json> = { ...document };
63	
64	  const conferences = document['conferences'];
65	  if (Array.isArray(conferences)) {
66	    next['conferences'] = conferences.map((conference: Json) => {
67	      if (!isObject(conference)) return conference;
68	      const conf: Record<string, Json> = { ...conference };
69	      const speakers = backfillItems(conference['speakers']);
70	      if (speakers !== undefined) conf['speakers'] = speakers;
71	      const seminars = backfillItems(conference['seminars']);
72	      if (seminars !== undefined) conf['seminars'] = seminars;
73	      return conf;
74	    });
75	  }
76	
77	  const team = backfillItems(document['team']);
78	  if (team !== undefined) next['team'] = team;
79	
80	  return next;
81	};

